1	/**
2	 * Layerinfinite — api/index.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Main Hono application entry point.
5	 *
6	 * Middleware order:
7	 *   1. Global: logger, CORS, secureHeaders, prettyJSON
8	 *   2. Rate limit on all /v1 routes (tiered by customer tier)
9	 *   3. Admin routes: authMiddleware + adminAuthMiddleware
10	 *   4. Agent routes: authMiddleware (or devAuthMiddleware)
11	 *   5. validateActionMiddleware on log-outcome only
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { Hono } from 'hono';
16	import { cors } from 'hono/cors';
17	import { logger } from 'hono/logger';
18	import { secureHeaders } from 'hono/secure-headers';
19	import { prettyJSON } from 'hono/pretty-json';
20	import { serve } from '@hono/node-server';
21	import * as Sentry from '@sentry/node';
22	
23	// Initialize BEFORE creating the Hono app
24	if (process.env.SENTRY_DSN) {
25	    Sentry.init({
26	        dsn: process.env.SENTRY_DSN,
27	        environment: process.env.NODE_ENV || 'production',
28	        tracesSampleRate: 0.1,  // 10% of requests traced
29	    });
30	}
31	
32	const REQUIRED_ENV_VARS = [
33	    'SUPABASE_URL',
34	    'SUPABASE_SERVICE_ROLE_KEY',
35	    'SUPABASE_ANON_KEY',
36	];
37	
38	if (process.env.NODE_ENV === 'production') {
39	    REQUIRED_ENV_VARS.push('LAYERINFINITE_INTERNAL_SECRET');
40	}
41	
42	const missing = REQUIRED_ENV_VARS.filter(
43	    v => !process.env[v]
44	);
45	
46	if (missing.length > 0) {
47	    console.error(
48	        '❌ FATAL: Missing required environment variables:\n' +
49	        missing.map(v => `  - ${v}`).join('\n') +
50	        '\n\nCopy .env.example to .env and fill in values.\n' +
51	        'See PRODUCTION_CHECKLIST.md for instructions.'
52	    );
53	    process.exit(1);
54	}
55	
56	// In development, LAYERINFINITE_DEV_API_KEY is optional 
57	// (falls back to real auth). Never required in production.
58	if (process.env.NODE_ENV !== 'production' &&
59	    !process.env.LAYERINFINITE_DEV_API_KEY) {
60	    console.warn(
61	        '⚠️  LAYERINFINITE_DEV_API_KEY not set. ' +
62	        'Dev bypass will require real API keys. ' +
63	        'Set it in .env for local testing convenience.'
64	    );
65	}
66	
67	import { authMiddleware, devAuthMiddleware } from './middleware/auth.js';
68	import { adminAuthMiddleware } from './middleware/admin-auth.js';
69	import { rateLimitMiddleware } from './middleware/rate-limit.js';
70	import { validateActionMiddleware } from './middleware/validate-action.js';
71	
72	import { logOutcomeRouter } from './routes/log-outcome.js';
73	import { getScoresRouter } from './routes/get-scores.js';
74	import { getPatternsRouter } from './routes/get-patterns.js';
75	import { auditRouter } from './routes/audit.js';
76	import { actionsRouter } from './routes/admin/actions.js';
77	import { reinstateAgentRouter } from './routes/admin/reinstate-agent.js';
78	import { reinstateSandboxRouter } from './routes/admin/reinstate-sandbox.js';
79	import { testNotificationRouter } from './routes/admin/test-notification.js';
80	import { triggerTrainingRoute } from './routes/admin/trigger-training.js';
81	import { restoreTrustSnapshotRouter } from './routes/admin/restore-trust-snapshot.js';
82	import { embeddingDriftRouter } from './routes/admin/embedding-drift.js';
83	import { userAuthMiddleware } from './middleware/user-auth.js';
84	import { apiKeysRouter } from './routes/auth/api-keys.js';
85	import { meRouter } from './routes/auth/me.js';
86	import { outcomeFeedbackRouter } from './routes/outcome-feedback.js';
87	import { simulateRouter } from './routes/simulate.js';
88	import contractsRoute from './routes/contracts.js';
89	import discrepancyRoute from './routes/discrepancy.js';
90	import pendingSignalsRoute from './routes/pending-signals.js';
91	import webhookRoute from './routes/webhook.js';
92	
93	// ── PORT: Railway injects PORT, fallback to API_PORT, then 3000 ──
94	const PORT = parseInt(process.env.PORT ?? process.env.API_PORT ?? '3000', 10);
95	
96	// ── FATAL: Dev bypass CANNOT be active in production ──────────
97	if (process.env.NODE_ENV === 'production' &&
98	    process.env.LAYERINFINITE_DEV_BYPASS === 'true') {
99	    console.error('FATAL: Dev bypass cannot be active in production. Set LAYERINFINITE_DEV_BYPASS=false.');
100	    process.exit(1);
101	}
102	
103	// ── Create app ────────────────────────────────────────────────
104	const app = new Hono();
105	
106	// ── CORS: env-driven origins ──────────────────────────────────
107	const allowedOrigins = process.env.ALLOWED_ORIGINS
108	    ? process.env.ALLOWED_ORIGINS.split(',').map(o => o.trim()).filter(Boolean)
109	    : ['http://localhost:3000', 'http://localhost:5173'];
110	
111	// Warn loudly in production if no https:// origin is configured
112	if (process.env.NODE_ENV === 'production') {
113	    const hasHttps = allowedOrigins.some(o => o.startsWith('https://'));
114	    if (!hasHttps) {
115	        console.warn(
116	            '⚠️  CORS WARNING: ALLOWED_ORIGINS contains no https:// URL in production.\n' +
117	            '   Current origins: ' + allowedOrigins.join(', ') + '\n' +
118	            '   All browser requests from your dashboard will be blocked.\n' +
119	            '   Set ALLOWED_ORIGINS=https://your-dashboard.vercel.app on Railway.'
120	        );
121	    }
122	}
123	
124	// ── Global middleware ─────────────────────────────────────────
125	app.use('*', logger());
126	app.use('*', secureHeaders());
127	app.use('*', cors({
128	    origin: (origin) => allowedOrigins.includes(origin) ? origin : null,
129	    allowHeaders: ['X-API-Key', 'X-Admin-Key', 'Authorization', 'Content-Type'],
130	    allowMethods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
131	    exposeHeaders: ['X-RateLimit-Limit', 'X-RateLimit-Remaining', 'X-RateLimit-Reset'],
132	}));
133	app.use('*', prettyJSON());
134	
135	// ── Global Timeout Middleware ─────────────────────────────────
136	const REQUEST_TIMEOUT_MS = parseInt(process.env.REQUEST_TIMEOUT_MS ?? '10000', 10);
137	
138	app.use('*', async (c, next) => {
139	    if (c.req.path === '/health' || c.req.path === '/health/deep' || c.req.path === '/') {
140	        return next();
141	    }
142	
143	    const controller = new AbortController();
144	    const timeoutId = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
145	    const start = Date.now();
146	
147	    try {
148	        await Promise.race([
149	            next(),
150	            new Promise((_, reject) => {
151	                controller.signal.addEventListener('abort',
152	                    () => reject(new Error('TIMEOUT')));
153	            })
154	        ]);
155	    } catch (e: any) {
156	        if (e?.message === 'TIMEOUT') {
157	            const elapsed = Date.now() - start;
158	            console.warn(`[layerinfinite] Request timeout on ${c.req.path} after ${elapsed}ms`);
159	            return c.json(
160	                { error: 'Request timeout', code: 'GATEWAY_TIMEOUT', timeout_ms: REQUEST_TIMEOUT_MS },
161	                504
162	            );
163	        }
164	        throw e;
165	    } finally {
166	        clearTimeout(timeoutId);
167	    }
168	});
169	
170	// ── Health check (no auth, no rate limiting) ──────────────────
171	app.get('/', (c) => c.json({
172	    service: 'Layerinfinite Decision Intelligence API',
173	    version: '1.0.0',
174	    status: 'healthy',
175	    timestamp: new Date().toISOString(),
176	    cors: {
177	        origins_count: allowedOrigins.length,
178	        has_production_origin: allowedOrigins.some(o => o.startsWith('https://')),
179	    },
180	    endpoints: {
181	        'POST /v1/log-outcome': 'Append outcome to fact_outcomes',
182	        'GET  /v1/get-scores': 'Get ranked action scores',
183	        'GET  /v1/get-patterns': 'Get action sequence patterns',
184	        'GET /v1/me': 'Verify API key identity — returns agent_id + customer_id',
185	        'GET  /v1/audit': 'Immutable audit trail',
186	        'POST /v1/admin/register-action': 'Register an action (admin)',
187	        'GET  /v1/admin/actions': 'List actions (admin)',
188	        'POST /v1/admin/reinstate-agent': 'Reinstate suspended agent (admin)',
189	        'POST /v1/admin/test-notification': 'Test a notification channel (admin)',
190	        'GET  /health/deep': 'Deep health check (table + env var diagnostics)',
191	    },
192	}));
193	
194	app.get('/health', async (c) => {
195	    const checks: Record<string, string> = { api: 'ok' };
196	    let overallStatus = 'ok';
197	
198	    try {
199	        const { supabase } = await import('./lib/supabase.js');
200	        const { error } = await supabase.from('dim_customers').select('customer_id').limit(1);
201	        checks.database = error ? 'error' : 'ok';
202	    } catch {
203	        checks.database = 'error';
204	    }
205	
206	    try {
207	        const { supabase } = await import('./lib/supabase.js');
208	        const { data, error } = await supabase
209	            .from('mv_action_scores')
210	            .select('view_refreshed_at')
211	            .limit(1);
212	
213	        if (error || !data || data.length === 0) {
214	            checks.materialized_view = 'stale';
215	        } else {
216	            const refreshedAt = new Date(data[0].view_refreshed_at);
217	            const ageMinutes = (Date.now() - refreshedAt.getTime()) / 60000;
218	            checks.materialized_view = ageMinutes > 15 ? 'stale' : 'ok';
219	        }
220	    } catch {
221	        checks.materialized_view = 'error';
222	    }
223	
224	    if (Object.values(checks).some(v => v === 'error')) {
225	        overallStatus = 'degraded';
226	    } else if (Object.values(checks).some(v => v === 'stale')) {
227	        overallStatus = 'degraded';
228	    }
229	
230	    return c.json({
231	        status: overallStatus,
232	        timestamp: new Date().toISOString(),
233	        checks,
234	        version: '1.0.0',
235	    });
236	});
237	
238	// ── Deep health check ───────────────────────────────────────
239	app.get('/health/deep', async (c) => {
240	    const checks: Record<string, string> = { api: 'ok' };
241	    let overallStatus = 'ok';
242	
243	    // ── Table reachability checks ──────────────────────────
244	    const tables = ['dim_agents', 'dim_customers', 'user_profiles', 'dim_actions', 'dim_contexts'] as const;
245	    try {
246	        const { supabase } = await import('./lib/supabase.js');
247	        for (const table of tables) {
248	            try {
249	                const { error } = await (supabase as any).from(table).select('*').limit(1);
250	                checks[`table_${table}`] = error ? `error: ${error.message}` : 'ok';
251	            } catch (e: any) {
252	                checks[`table_${table}`] = `error: ${e.message}`;
253	            }
254	        }
255	    } catch (e: any) {
256	        for (const table of tables) checks[`table_${table}`] = 'error: supabase unavailable';
257	    }
258	
259	    // ── Schema version ─────────────────────────────────────
260	    try {
261	        const { supabase } = await import('./lib/supabase.js');
262	        const { data, error } = await supabase
263	            .from('schema_migrations')
264	            .select('version')
265	            .order('version', { ascending: false })
266	            .limit(1);
267	        checks.schema_version = (!error && data && data.length > 0)
268	            ? `v${data[0].version}`
269	            : 'unknown';
270	    } catch {
271	        checks.schema_version = 'unknown';
272	    }
273	
274	    // ── Environment variable checks ────────────────────────
275	    checks.env_ALLOWED_ORIGINS = process.env.ALLOWED_ORIGINS
276	        ? `set (${allowedOrigins.length} origins)`
277	        : 'missing';
278	    checks.env_LAYERINFINITE_INTERNAL_SECRET = process.env.LAYERINFINITE_INTERNAL_SECRET
279	        ? 'set'
280	        : 'missing';
281	    checks.env_SUPABASE_URL = process.env.SUPABASE_URL ? 'set' : 'missing';
282	    checks.env_SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY ? 'set' : 'missing';
283	
284	    // ── Existing materialized view check ──────────────────
285	    try {
286	        const { supabase } = await import('./lib/supabase.js');
287	        const { data, error } = await supabase
288	            .from('mv_action_scores')
289	            .select('view_refreshed_at')
290	            .limit(1);
291	        if (error || !data || data.length === 0) {
292	            checks.materialized_view = 'stale';
293	        } else {
294	            const ageMinutes = (Date.now() - new Date(data[0].view_refreshed_at).getTime()) / 60000;
295	            checks.materialized_view = ageMinutes > 15 ? 'stale' : 'ok';
296	        }
297	    } catch {
298	        checks.materialized_view = 'error';
299	    }
300	
301	    // ── mv_episode_patterns: regression guard ──────────────
302	    // Catches if the MV is rebuilt against the wrong source table (bug from migration 064).
303	    // Only warns if fact_outcomes already has episode rows — fresh deploys are fine at 0.
304	    try {
305	        const { supabase } = await import('./lib/supabase.js');
306	        const { count: outcomeCount } = await supabase
307	            .from('fact_outcomes')
308	            .select('*', { count: 'exact', head: true })
309	            .not('episode_id', 'is', null);
310	        const { count: patternCount, error: mvErr } = await supabase
311	            .from('mv_episode_patterns')
312	            .select('*', { count: 'exact', head: true });
313	        if (mvErr) {
314	            checks.mv_episode_patterns = `error: ${mvErr.message}`;
315	        } else if ((outcomeCount ?? 0) > 5 && (patternCount ?? 0) === 0) {
316	            checks.mv_episode_patterns = 'warn: 0 patterns but outcomes exist — run refresh_mv_episode_patterns()';
317	        } else {
318	            checks.mv_episode_patterns = `ok (${patternCount ?? 0} patterns)`;
319	        }
320	    } catch {
321	        checks.mv_episode_patterns = 'error';
322	    }
323	
324	    // ── Schema invariants (via DB function) ────────────────
325	    // verify_schema_invariants() is defined in migration 065.
326	    // Checks: action_sequences FK absent, event_type values valid.
327	    try {
328	        const { supabase } = await import('./lib/supabase.js');
329	        const { data, error } = await supabase.rpc('verify_schema_invariants' as any);
330	        if (error) {
331	            checks.schema_invariants = 'unknown (function not found — run migration 065)';
332	        } else {
333	            const result = data as { pass: boolean; failures: string[] };
334	            checks.schema_invariants = result.pass
335	                ? 'ok'
336	                : `FAIL: ${result.failures.join(', ')}`;
337	        }
338	    } catch {
339	        checks.schema_invariants = 'unknown';
340	    }
341	
342	    // ── Overall status calculation ─────────────────────────
343	    const vals = Object.values(checks);
344	    if (vals.some(v => v.startsWith('error') || v === 'missing')) {
345	        overallStatus = 'degraded';
346	    } else if (vals.some(v => v === 'stale' || v === 'unknown')) {
347	        overallStatus = 'degraded';
348	    }
349	
350	    return c.json({
351	        status: overallStatus,
352	        timestamp: new Date().toISOString(),
353	        checks,
354	        version: '1.0.0',
355	    }, overallStatus === 'ok' ? 200 : 200); // always 200, let callers read 'status'
356	});
357	
358	// ── Internal: scoring cache refresh ───────────────────────────
359	app.post('/internal/refresh-score-cache', async (c) => {
360	    const auth = c.req.header('Authorization');
361	    const internalSecret = process.env.LAYERINFINITE_INTERNAL_SECRET;
362	    if (!internalSecret || auth !== `Bearer ${internalSecret}`) {
363	        return c.json({ error: 'Unauthorized' }, 401);
364	    }
365	    const { invalidateCache } = await import('./lib/scoring.js');
366	    invalidateCache();
367	    return c.json({ ok: true, message: 'Score cache cleared' });
368	});
369	
370	// ── v1 API ────────────────────────────────────────────────────
371	const v1 = new Hono();
372	
373	const primaryAuth = process.env.NODE_ENV === 'production'
374	    ? authMiddleware
375	    : devAuthMiddleware;
376	
377	const authRoutes = new Hono();
378	authRoutes.use('*', userAuthMiddleware);
379	authRoutes.use('*', rateLimitMiddleware());
380	authRoutes.route('/api-keys', apiKeysRouter);
381	authRoutes.route('/keys', apiKeysRouter);
382	v1.route('/auth', authRoutes);
383	
384	v1.use('/me', primaryAuth);
385	v1.route('/me', meRouter);
386	
387	v1.use('/admin/*', adminAuthMiddleware);
388	v1.route('/admin', actionsRouter);
389	v1.route('/admin/reinstate-agent', reinstateAgentRouter);
390	v1.route('/admin', reinstateSandboxRouter);
391	v1.route('/admin/test-notification', testNotificationRouter);
392	v1.route('/admin/trigger-training', triggerTrainingRoute);
393	v1.route('/admin/restore-trust-snapshot', restoreTrustSnapshotRouter);
394	v1.route('/admin/embedding-drift', embeddingDriftRouter);
395	
396	v1.use('/log-outcome', primaryAuth, rateLimitMiddleware(), validateActionMiddleware);
397	v1.use('/log-outcome/*', primaryAuth, rateLimitMiddleware(), validateActionMiddleware);
398	v1.use('/outcome-feedback', primaryAuth, rateLimitMiddleware());
399	v1.use('/outcome-feedback/*', primaryAuth, rateLimitMiddleware());
400	v1.use('/get-scores', primaryAuth, rateLimitMiddleware());
401	v1.use('/get-scores/*', primaryAuth, rateLimitMiddleware());
402	v1.use('/get-patterns', primaryAuth, rateLimitMiddleware());
403	v1.use('/get-patterns/*', primaryAuth, rateLimitMiddleware());
404	v1.use('/audit', primaryAuth, rateLimitMiddleware());
405	v1.use('/audit/*', primaryAuth, rateLimitMiddleware());
406	v1.use('/simulate', primaryAuth, rateLimitMiddleware());
407	v1.use('/simulate/*', primaryAuth, rateLimitMiddleware());
408	
409	v1.route('/log-outcome', logOutcomeRouter);
410	v1.route('/outcome-feedback', outcomeFeedbackRouter);
411	v1.route('/get-scores', getScoresRouter);
412	v1.route('/get-patterns', getPatternsRouter);
413	v1.route('/audit', auditRouter);
414	v1.route('/simulate', simulateRouter);
415	
416	app.route('/v1', v1);
417	app.route('/v1/contracts', contractsRoute);
418	app.route('/v1/discrepancies', discrepancyRoute);
419	app.route('/v1/pending-signals', pendingSignalsRoute);
420	app.post('/v1/webhook/:provider', webhookRoute);
421	
422	// ── 404 fallback ──────────────────────────────────────────────
423	app.notFound((c) => c.json(
424	    { error: 'Route not found', code: 'NOT_FOUND', available_prefix: '/v1' },
425	    404
426	));
427	
428	// ── Global error handler ──────────────────────────────────────
429	app.onError((err, c) => {
430	    if (process.env.SENTRY_DSN) {
431	        Sentry.captureException(err, {
432	            extra: {
433	                path: c.req.path,
434	                method: c.req.method,
435	            },
436	        });
437	    }
438	
439	    console.error('[layerinfinite] Unhandled error:', err.message);
440	    return c.json(
441	        { error: 'Internal server error', code: 'INTERNAL_ERROR', message: err.message },
442	        500
443	    );
444	});
445	
446	// ── Start server ──────────────────────────────────────────────
447	serve({
448	    fetch: app.fetch,
449	    port: PORT,
450	}, (info) => {
451	    console.log(`\n🚀 Layerinfinite API running on port ${info.port}`);
452	    console.log(`   Mode:       ${process.env.NODE_ENV ?? 'development'}`);
453	    console.log(`   Dev bypass: ${process.env.LAYERINFINITE_DEV_BYPASS === 'true' ? '⚠️  ACTIVE' : 'disabled'}`);
454	    console.log(`   Endpoints:  POST /v1/log-outcome | GET /v1/get-scores | GET /v1/get-patterns | GET /v1/audit`);
455	    console.log(`   Admin:      POST /v1/admin/register-action | GET /v1/admin/actions | POST /v1/admin/reinstate-agent`);
456	    console.log(`   Rate limit: Tiered (1K/2K/5K per min by customer tier)\n`);
457	});
458

1	/**
2	 * Layerinfinite — routes/get-patterns.ts
3	 * GET /v1/get-patterns
4	 * ══════════════════════════════════════════════════════════════
5	 * Returns the most successful action sequences (episodes)
6	 * for a given context. Powers "pattern-based recommendations"
7	 * which go beyond single-action scoring by returning whole
8	 * playbooks (ordered sequences of actions that resolved issues).
9	 * Reads from mv_episode_patterns (refreshed nightly).
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { Hono } from 'hono';
14	import { supabase } from '../lib/supabase.js';
15	
16	export const getPatternsRouter = new Hono();
17	
18	// ── GET /v1/get-patterns ──────────────────────────────────────
19	getPatternsRouter.get('/', async (c) => {
20	    const customerId = c.get('customer_id') as string;
21	
22	    const issueType = c.req.query('issue_type');
23	    const contextId = c.req.query('context_id');
24	    const minSamples = parseInt(c.req.query('min_samples') ?? '2', 10);
25	    const topN = parseInt(c.req.query('top_n') ?? '5', 10);
26	
27	    if (!issueType && !contextId) {
28	        return c.json(
29	            { error: 'Provide either issue_type or context_id', code: 'MISSING_PARAM' },
30	            400
31	        );
32	    }
33	
34	    // ── Resolve context_id ────────────────────────────────────
35	    let resolvedContextId = contextId;
36	
37	    if (!resolvedContextId && issueType) {
38	        const { data, error } = await supabase
39	            .from('dim_contexts')
40	            .select('context_id')
41	            .eq('issue_type', issueType)
42	            .limit(1)
43	            .maybeSingle();
44	
45	        if (error) {
46	            return c.json({ error: 'Context lookup failed', details: error.message }, 500);
47	        }
48	        if (!data) {
49	            return c.json(
50	                {
51	                    patterns: [],
52	                    total_found: 0,
53	                    context_id: null,
54	                    issue_type: issueType,
55	                    message: `No patterns yet for "${issueType}". Patterns appear after 2+ complete episodes.`,
56	                    cold_start: true,
57	                },
58	                200
59	            );
60	        }
61	        resolvedContextId = data.context_id;
62	    }
63	
64	    // ── Fetch patterns from materialized view ─────────────────
65	    const { data: patterns, error } = await supabase
66	        .from('mv_episode_patterns')
67	        .select('*')
68	        .eq('customer_id', customerId)
69	        .eq('context_id', resolvedContextId)
70	        .gte('sample_count', minSamples)
71	        .gte('episode_success_rate', 0.5)     // only show patterns with >50% success
72	        .order('episode_success_rate', { ascending: false })
73	        .limit(Math.min(topN, 20));
74	
75	    if (error) {
76	        return c.json({ error: 'Pattern query failed', details: error.message, code: 'DB_ERROR' }, 500);
77	    }
78	
79	    if (!patterns || patterns.length === 0) {
80	        return c.json({
81	            patterns: [],
82	            total_found: 0,
83	            context_id: resolvedContextId,
84	            issue_type: issueType ?? null,
85	            message: 'No patterns found yet. Patterns appear after 2+ complete episodes with shared action sequences.',
86	            cold_start: true,
87	        }, 200);
88	    }
89	
90	    // ── Enrich action_sequence with names ─────────────────────
91	    // action_sequence is stored as [{action_id, success, ...}, ...]
92	    // Batch-resolve action names from dim_actions
93	    const allActionIds = new Set<string>();
94	    patterns.forEach((p: any) => {
95	        const seq = p.action_sequence ?? [];
96	        seq.forEach((step: any) => {
97	            if (step?.action_id) allActionIds.add(step.action_id);
98	        });
99	    });
100	
101	    let actionNameMap: Record<string, string> = {};
102	    if (allActionIds.size > 0) {
103	        const { data: actions } = await supabase
104	            .from('dim_actions')
105	            .select('action_id, action_name')
106	            .in('action_id', Array.from(allActionIds));
107	
108	        if (actions) {
109	            actionNameMap = Object.fromEntries(actions.map((a: any) => [a.action_id, a.action_name]));
110	        }
111	    }
112	
113	    const enriched = patterns.map((p: any) => ({
114	        context_id: p.context_id,
115	        customer_id: p.customer_id,
116	        episode_success_rate: p.episode_success_rate,
117	        avg_duration_ms: p.avg_duration_ms,
118	        sample_count: p.sample_count,
119	        last_seen_at: p.last_seen_at,
120	        view_refreshed_at: p.view_refreshed_at,
121	        action_sequence: (p.action_sequence ?? []).map((step: any) => ({
122	            ...step,
123	            action_name: actionNameMap[step?.action_id] ?? step?.action_id,
124	        })),
125	    }));
126	
127	    return c.json({
128	        patterns: enriched,
129	        total_found: enriched.length,
130	        context_id: resolvedContextId,
131	        issue_type: issueType ?? null,
132	        cold_start: false,
133	    });
134	});
