1	/**
2	 * Layerinfinite — routes/audit.ts
3	 * GET /v1/audit
4	 * ══════════════════════════════════════════════════════════════
5	 * Immutable audit trail for compliance teams.
6	 * Returns a paginated list of logged outcomes (fact_outcomes)
7	 * with filtering by session, action, time range.
8	 * ALL data is read-only. No mutations possible.
9	 * GDPR: soft-deleted rows (is_deleted=TRUE) are excluded.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { Hono } from 'hono';
14	import { supabase } from '../lib/supabase.js';
15	
16	export const auditRouter = new Hono();
17	
18	const MAX_PAGE_SIZE = 100;
19	const DEFAULT_PAGE_SIZE = 50;
20	
21	// ── GET /v1/audit ─────────────────────────────────────────────
22	auditRouter.get('/', async (c) => {
23	    const customerId = c.get('customer_id') as string;
24	
25	    const sessionId = c.req.query('session_id');
26	    const actionName = c.req.query('action_name');
27	    const agentId = c.req.query('agent_id');
28	    const success = c.req.query('success');     // 'true' | 'false' | undefined
29	    const from = c.req.query('from');         // ISO date string
30	    const to = c.req.query('to');           // ISO date string
31	    const cursor = c.req.query('cursor');
32	    const pageStr = c.req.query('page');
33	    const offsetStr = c.req.query('offset');
34	    const sizeStr = c.req.query('page_size') ?? c.req.query('limit') ?? String(DEFAULT_PAGE_SIZE);
35	
36	    const page = Math.max(1, parseInt(pageStr ?? '1', 10) || 1);
37	    const pageSize = Math.min(MAX_PAGE_SIZE, Math.max(1, parseInt(sizeStr, 10) || DEFAULT_PAGE_SIZE));
38	
39	    // ── Build query ───────────────────────────────────────────
40	    let query = supabase
41	        .from('fact_outcomes')
42	        .select(`
43	      outcome_id,
44	      session_id,
45	      timestamp,
46	      success,
47	      response_time_ms,
48	      error_code,
49	      error_message,
50	      is_synthetic,
51	      salience_score,
52	      dim_agents!inner(agent_id, agent_name, agent_type),
53	      dim_actions!inner(action_id, action_name, action_category),
54	      dim_contexts!inner(context_id, issue_type, environment)
55	    `, { count: 'exact' })
56	        .eq('customer_id', customerId)
57	        .eq('is_deleted', false)           // GDPR: exclude soft-deleted
58	        .order('timestamp', { ascending: false })
59	        .order('outcome_id', { ascending: false })  // secondary sort: stable pagination across tied timestamps
60	        .limit(pageSize);
61	
62	    if (cursor) {
63	        try {
64	            const { ts, id } = JSON.parse(Buffer.from(cursor, 'base64').toString('utf-8'));
65	            // Validate before interpolation to prevent PostgREST filter injection.
66	            // ts must be an ISO 8601 timestamp; id must be a UUID.
67	            const ISO_TS = /^\d{4}-\d{2}-\d{2}T[\d:.]+(?:Z|[+-]\d{2}:\d{2})?$/;
68	            const UUID   = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
69	            if (typeof ts !== 'string' || typeof id !== 'string' || !ISO_TS.test(ts) || !UUID.test(id)) {
70	                throw new Error('invalid cursor shape');
71	            }
72	            // Composite row-value comparison (descending): skip rows at or before the cursor position.
73	            // Handles ties at page boundaries: same timestamp rows are ordered by outcome_id descending.
74	            query = query.or(`timestamp.lt.${ts},and(timestamp.eq.${ts},outcome_id.lt.${id})`);
75	        } catch {
76	            // Malformed or invalid cursor — ignore and return from the beginning
77	        }
78	    } else if (pageStr || offsetStr) {
79	        // Fallback for legacy offset pagination
80	        const offset = offsetStr ? parseInt(offsetStr, 10) : (page - 1) * pageSize;
81	        if (!isNaN(offset)) {
82	            query = query.range(offset, offset + pageSize - 1);
83	        }
84	    }
85	
86	    // ── Apply filters ─────────────────────────────────────────
87	    if (sessionId) query = query.eq('session_id', sessionId);
88	    if (agentId) query = query.eq('agent_id', agentId);
89	    if (success !== undefined) {
90	        query = query.eq('success', success === 'true');
91	    }
92	    if (from) query = query.gte('timestamp', from);
93	    if (to) query = query.lte('timestamp', to);
94	
95	    // Filter by action_name (via joined table)
96	    if (actionName) {
97	        // Supabase supports filtering on joined tables
98	        query = (query as any).eq('dim_actions.action_name', actionName);
99	    }
100	
101	    const { data, error, count } = await query;
102	
103	    if (error) {
104	        console.error('[audit] Query error:', error.message);
105	        return c.json({ error: 'Audit query failed', details: error.message, code: 'DB_ERROR' }, 500);
106	    }
107	
108	    const totalPages = Math.ceil((count ?? 0) / pageSize);
109	    // hasMore is true only when we filled a full page AND the DB has more rows beyond it.
110	    // Avoids false positives when total rows is an exact multiple of pageSize.
111	    const hasMore = (data?.length ?? 0) === pageSize && (count ?? 0) > (data?.length ?? 0);
112	    const lastRow = hasMore ? data![data!.length - 1] : null;
113	    const nextCursor = (lastRow?.timestamp && lastRow?.outcome_id)
114	        ? Buffer.from(JSON.stringify({ ts: lastRow.timestamp, id: lastRow.outcome_id })).toString('base64')
115	        : null;
116	
117	    return c.json({
118	        outcomes: (data ?? []).map((row: any) => ({
119	            outcome_id: row.outcome_id,
120	            session_id: row.session_id,
121	            timestamp: row.timestamp,
122	            success: row.success,
123	            response_time_ms: row.response_time_ms,
124	            error_code: row.error_code,
125	            error_message: row.error_message,
126	            is_synthetic: row.is_synthetic,
127	            salience_score: row.salience_score,
128	            agent: row.dim_agents ? {
129	                id: row.dim_agents.agent_id,
130	                name: row.dim_agents.agent_name,
131	                type: row.dim_agents.agent_type,
132	            } : null,
133	            action: row.dim_actions ? {
134	                id: row.dim_actions.action_id,
135	                name: row.dim_actions.action_name,
136	                category: row.dim_actions.action_category,
137	            } : null,
138	            context: row.dim_contexts ? {
139	                id: row.dim_contexts.context_id,
140	                issue_type: row.dim_contexts.issue_type,
141	                environment: row.dim_contexts.environment,
142	            } : null,
143	        })),
144	        pagination: {
145	            page,
146	            page_size: pageSize,
147	            total_rows: count ?? 0,
148	            total_pages: totalPages,
149	            has_next: page < totalPages,
150	            has_prev: page > 1,
151	            // Keyset fields
152	            next_cursor: nextCursor,
153	            has_more: hasMore,
154	        },
155	        pagination_warning: (pageStr || offsetStr) ? 'page/offset parameters deprecated. Use cursor.' : undefined,
156	        filters: {
157	            session_id: sessionId ?? null,
158	            action_name: actionName ?? null,
159	            agent_id: agentId ?? null,
160	            success: success ?? null,
161	            from: from ?? null,
162	            to: to ?? null,
163	        },
164	        note: 'This audit trail is immutable. All rows reflect append-only fact_outcomes.',
165	    });
166	});
167	
168	// ── GET /v1/audit/:outcome_id — Single outcome detail ─────────
169	auditRouter.get('/:outcome_id', async (c) => {
170	    const customerId = c.get('customer_id') as string;
171	    const outcomeId = c.req.param('outcome_id');
172	
173	    const { data, error } = await supabase
174	        .from('fact_outcomes')
175	        .select(`
176	      *,
177	      dim_agents!inner(agent_id, agent_name, agent_type, llm_model),
178	      dim_actions!inner(action_id, action_name, action_category, action_description),
179	      dim_contexts!inner(context_id, issue_type, environment, customer_tier)
180	    `)
181	        .eq('outcome_id', outcomeId)
182	        .eq('customer_id', customerId)
183	        .eq('is_deleted', false)
184	        .maybeSingle();
185	
186	    if (error) {
187	        return c.json({ error: 'Query failed', details: error.message }, 500);
188	    }
189	    if (!data) {
190	        return c.json({ error: `Outcome ${outcomeId} not found`, code: 'NOT_FOUND' }, 404);
191	    }
192	
193	    return c.json({ outcome: data });
194	});
