1	/**
2	 * Layerinfinite — routes/get-scores.ts
3	 * GET /v1/get-scores
4	 * ══════════════════════════════════════════════════════════════
5	 * Returns ranked action scores for a given context.
6	 * Reads from mv_action_scores (never raw fact_outcomes).
7	 * Uses context-embed.ts for similarity matching.
8	 * Returns policy recommendation from policy engine.
9	 * ══════════════════════════════════════════════════════════════
10	 */
11	
12	import { Hono } from 'hono';
13	import crypto from 'node:crypto';
14	import { getScores, ScoredAction } from '../lib/scoring.js';
15	import { supabase } from '../lib/supabase.js';
16	import { bufferDecision } from '../lib/decision-writer.js';
17	import { generateEmbedding, findClosestContext, buildContextText } from '../lib/context-embed.js';
18	import {
19	    getPolicyDecision,
20	    DEFAULT_TRUST,
21	    DEFAULT_POLICY_CONFIG,
22	    AgentTrustScore,
23	    CustomerPolicyConfig,
24	} from '../lib/policy-engine.js';
25	import { computePropensities, RankedActionEntry } from '../lib/ips-engine.js';
26	
27	// ── Helper: fetch real agent trust from DB (falls back to DEFAULT_TRUST) ──
28	async function getAgentTrust(agentId: string | undefined): Promise<AgentTrustScore> {
29	    if (!agentId) return DEFAULT_TRUST;
30	    const { data, error } = await supabase
31	        .from('agent_trust_scores')
32	        .select('trust_score, trust_status, consecutive_failures')
33	        .eq('agent_id', agentId)
34	        .maybeSingle();
35	    if (error || !data) return DEFAULT_TRUST;
36	    return {
37	        trust_score: data.trust_score,
38	        trust_status: data.trust_status,
39	        consecutive_failures: data.consecutive_failures,
40	    };
41	}
42	
43	// ── Helper: fetch real customer config from DB (falls back to DEFAULT_POLICY_CONFIG) ──
44	async function getCustomerConfig(customerId: string): Promise<CustomerPolicyConfig> {
45	    const { data, error } = await supabase
46	        .from('dim_customers')
47	        .select('config')
48	        .eq('customer_id', customerId)
49	        .maybeSingle();
50	    if (error || !data?.config) return DEFAULT_POLICY_CONFIG;
51	    const cfg = data.config as Record<string, unknown>;
52	    return {
53	        risk_tolerance: (['conservative', 'balanced', 'aggressive'].includes(cfg.risk_tolerance as string)
54	            ? cfg.risk_tolerance : 'balanced') as CustomerPolicyConfig['risk_tolerance'],
55	        escalation_score: typeof cfg.escalation_score === 'number' ? cfg.escalation_score : 0.20,
56	        exploration_rate: typeof cfg.exploration_rate === 'number' ? cfg.exploration_rate : 0.05,
57	        min_confidence: typeof cfg.min_confidence === 'number' ? cfg.min_confidence : 0.30,
58	    };
59	}
60	
61	const STALE_THRESHOLD_MINUTES = 10;
62	
63	export const getScoresRouter = new Hono();
64	
65	// ── GET /v1/get-scores ────────────────────────────────────────
66	getScoresRouter.get('/', async (c) => {
67	    const customerId = c.get('customer_id') as string;
68	
69	    const agentId = c.get('agent_id') as string | undefined;
70	
71	    // ── Query params ──────────────────────────────────────────
72	    const issueType = c.req.query('issue_type');
73	    const contextId = c.req.query('context_id');
74	    const forceRefresh = c.req.query('refresh') === 'true';
75	    const topN = parseInt(c.req.query('top_n') ?? '10', 10);
76	
77	    // ── New optional params (backward compatible) ─────────────
78	    const episodeId = c.req.query('episode_id') ?? null;
79	    const episodeHistoryRaw = c.req.query('episode_history') ?? null;
80	    let episodeHistory: string[] | null = null;
81	    if (episodeHistoryRaw) {
82	        try {
83	            const parsed = JSON.parse(episodeHistoryRaw);
84	            if (Array.isArray(parsed)) episodeHistory = parsed;
85	        } catch {
86	            // Invalid JSON — ignore, treat as no history
87	        }
88	    }
89	
90	    // ── Fetch real trust + customer config in parallel ────────
91	    const [agentTrust, customerConfig] = await Promise.all([
92	        getAgentTrust(agentId),
93	        getCustomerConfig(customerId),
94	    ]);
95	
96	    if (!issueType && !contextId) {
97	        return c.json(
98	            { error: 'Provide either issue_type or context_id query parameter', code: 'MISSING_PARAM', agent_id: '', signal_contract: null },
99	            400
100	        );
101	    }
102	
103	    // ── Resolve context_id ───────────────────────────────────
104	    let resolvedContextId = contextId;
105	    let contextMatch: number | null = null;  // null = exact match
106	
107	    if (!resolvedContextId && issueType) {
108	        // Step 1: Try exact string match (fast path) — scoped to this customer
109	        const { data: exactCtx, error } = await supabase
110	            .from('dim_contexts')
111	            .select('context_id')
112	            .eq('customer_id', customerId)
113	            .eq('issue_type', issueType)
114	            .order('created_at', { ascending: false })
115	            .limit(1)
116	            .maybeSingle();
117	
118	        if (error) {
119	            return c.json({ error: 'Context lookup failed', details: error.message, code: 'DB_ERROR' }, 500);
120	        }
121	
122	        if (exactCtx) {
123	            resolvedContextId = exactCtx.context_id;
124	            contextMatch = null;  // exact match → treated as 1.0
125	        } else {
126	            // Step 2: Try embedding similarity (graceful fallback)
127	            try {
128	                const contextText = buildContextText(issueType);
129	                const embedding = await generateEmbedding(contextText);
130	
131	                if (embedding) {
132	                    const closest = await findClosestContext(embedding, customerId);
133	                    if (closest) {
134	                        resolvedContextId = closest.context_id;
135	                        contextMatch = closest.similarity;
136	                    }
137	                }
138	            } catch (err: any) {
139	                // Embedding failed — fall through to 404
140	                console.warn('[get-scores] Embedding fallback failed:', err.message);
141	            }
142	
143	            // If still no context found → cold start (200, not 404)
144	            if (!resolvedContextId) {
145	                return c.json({
146	                    ranked_actions:    [],
147	                    top_action:        null,
148	                    cold_start:        true,
149	                    context_id:        '',
150	                    agent_id:          agentId ?? '',
151	                    policy:            'explore',
152	                    policy_reason:     'No prior context — cold start active',
153	                    served_from_cache: false,
154	                    cold_start_warning: {
155	                        message:        `No context found for issue_type="${issueType}". Cold-start active.`,
156	                        recommendation: 'Log at least one outcome to seed this context.',
157	                    },
158	                    signal_contract: null,
159	                }, 200);
160	            }
161	        }
162	    }
163	
164	    // ── Fetch and score actions ───────────────────────────────
165	    try {
166	        const result = await getScores(
167	            customerId,
168	            resolvedContextId!,
169	            issueType ?? undefined,
170	            forceRefresh,
171	            contextMatch
172	        );
173	
174	        // Trim to top_n
175	        let ranked = result.ranked_actions.slice(0, Math.min(topN, 50));
176	
177	        // ── Deprioritize already-tried actions (CHANGE 4) ────
178	        if (episodeHistory && episodeHistory.length > 0) {
179	            ranked = ranked.map(action => {
180	                if (episodeHistory!.includes(action.action_name)) {
181	                    return {
182	                        ...action,
183	                        composite_score: action.composite_score * 0.3,
184	                        recommendation: 'avoid' as const,
185	                    };
186	                }
187	                return action;
188	            });
189	            // Re-sort after deprioritization
190	            ranked.sort((a, b) => b.composite_score - a.composite_score);
191	        }
192	
193	        // ── Context drift check (Gap 2) ──────────────────────
194	        const { count: contextOutcomeCount } = await supabase
195	            .from('mv_action_scores')
196	            .select('action_id', { count: 'exact', head: true })
197	            .eq('customer_id', customerId)
198	            .eq('context_id', resolvedContextId!);
199	
200	        const isUnknownContext = (contextOutcomeCount ?? 0) === 0;
201	
202	        // ── Compute propensities for ranked actions ──────────
203	        const propensityMap = computePropensities(
204	            ranked.map(a => ({ action_name: a.action_name, score: a.composite_score }))
205	        );
206	
207	        // Build ranked actions with propensities
208	        const rankedWithPropensity: RankedActionEntry[] = ranked.map((a, idx) => ({
209	            action_name: a.action_name,
210	            action_id: a.action_id,
211	            score: a.composite_score,
212	            rank: idx + 1,
213	            propensity: propensityMap.get(a.action_name) ?? 0,
214	        }));
215	
216	        // ── Create fact_decisions record (CHANGE 2) ──────────
217	        let decisionId: string | null = null;
218	        const contextHash = `${resolvedContextId}:${issueType ?? ''}`;
219	        const episodePosition = episodeHistory ? episodeHistory.length : 0;
220	        
221	        if (episodeId) {
222	            decisionId = bufferDecision({
223	                agent_id: agentId ?? null,
224	                context_id: resolvedContextId!,
225	                context_hash: contextHash,
226	                ranked_actions: rankedWithPropensity,
227	                episode_id: episodeId,
228	                episode_position: episodePosition,
229	            });
230	        }
231	
232	        // ── Sequence recommendation (CHANGE 3) ───────────────
233	        let recommendedSequence: {
234	            actions: string[];
235	            predicted_outcome: number;
236	            confidence: number;
237	            prediction_interval: [number, number];
238	            simulation_tier: 1 | 2 | 3;
239	            tier_explanation: string;
240	        } | null = null;
241	
242	        if (episodeHistory && episodeHistory.length > 0) {
243	            try {
244	                const { data: seqData } = await supabase
245	                    .from('mv_sequence_scores')
246	                    .select('*')
247	                    .eq('context_hash', contextHash)
248	                    .gte('sample_count', 3);
249	
250	                if (seqData && seqData.length > 0) {
251	                    // Find sequences that start with current episode history
252	                    const matching = seqData.filter((seq: any) => {
253	                        const seqActions: string[] = seq.action_sequence ?? [];
254	                        if (seqActions.length <= episodeHistory!.length) return false;
255	                        return episodeHistory!.every((a, i) => seqActions[i] === a);
256	                    });
257	
258	                    if (matching.length > 0) {
259	                        // Pick highest mean_outcome
260	                        const best = matching.reduce((a: any, b: any) =>
261	                            (b.mean_outcome ?? 0) > (a.mean_outcome ?? 0) ? b : a
262	                        );
263	                        recommendedSequence = {
264	                            actions: best.action_sequence,
265	                            predicted_outcome: best.mean_outcome ?? 0,
266	                            confidence: best.wilson_ci_lower ?? 0,
267	                            prediction_interval: [best.wilson_ci_lower ?? 0, best.wilson_ci_upper ?? 1],
268	                            simulation_tier: 1,
269	                            tier_explanation: 'Tier 1: Empirical sequence scores from observed data',
270	                        };
271	                    }
272	                }
273	            } catch (err: any) {
274	                console.warn('[get-scores] Sequence lookup failed:', err.message);
275	            }
276	        }
277	
278	        // ── Sequence context ─────────────────────────────────
279	        const sequenceContext = episodeHistory ? {
280	            episode_position: episodeHistory.length,
281	            actions_tried: episodeHistory,
282	            already_resolved: false,  // caller can check via episode state
283	        } : null;
284	
285	        // ── Policy recommendation ────────────────────────────
286	        const policy = getPolicyDecision({
287	            rankedActions: ranked,
288	            agentTrust: agentTrust,
289	            customerConfig: customerConfig,
290	            coldStartActive: result.cold_start,
291	        });
292	
293	        // ── Staleness signal ─────────────────────────────────
294	        const lastRefresh = result.view_refreshed_at ?? null;
295	        const ageMinutes = lastRefresh
296	            ? (Date.now() - new Date(lastRefresh).getTime()) / 60_000
297	            : null;
298	        const isStale = ageMinutes !== null && ageMinutes > STALE_THRESHOLD_MINUTES;
299	
300	        return c.json({
301	            ranked_actions: ranked,
302	            top_action: result.top_action,
303	            should_escalate: result.should_escalate,
304	            cold_start: result.cold_start,
305	            context_id: resolvedContextId,
306	            agent_id: agentId ?? '',
307	            customer_id: customerId,
308	            issue_type: issueType ?? null,
309	            context_match: contextMatch,
310	            context_warning: isUnknownContext ? {
311	                type: 'context_drift',
312	                message: 'No outcome history for this context type.',
313	                recommendation: 'Cold-start protocol active. Scores are based on priors only.',
314	                confidence_cap: 0.3,
315	            } : null,
316	            view_refreshed_at: result.view_refreshed_at,
317	            scores_as_of: result.view_refreshed_at,
