197	async function parseAndSanitizeRequest(c: Context) {
198	    let body: z.infer<typeof LogOutcomeBody>;
199	    try {
200	        const raw = c.get('parsed_body') ?? await c.req.json();
201	        body = LogOutcomeBody.parse(raw);
202	    } catch (err: any) {
203	        // Surface field-level zod errors so callers know exactly what's missing
204	        const details = err.errors
205	            ? err.errors.map((e: any) => `${e.path.join('.')}: ${e.message}`).join(', ')
206	            : err.message;
207	        throw new Error(`VALIDATION_ERROR:${details}`);
208	    }
209	
210	    // Auto-generate session_id when SDK does not send it
211	    if (!body.session_id) {
212	        body.session_id = crypto.randomUUID();
213	    }
214	
215	    // Normalize response_ms (SDK alias) → response_time_ms
216	    (body as any).response_time_ms = body.response_time_ms ?? (body as any).response_ms ?? null;
217	
218	    if (body.raw_context) body.raw_context = sanitizeContext(body.raw_context);
219	    if (body.error_message) body.error_message = sanitizeString(body.error_message, 1000);
220	    if (body.error_code) body.error_code = sanitizeString(body.error_code, 100);
221	
222	    // Payload size check
223	    if (body.raw_context) {
224	        const contextSize = new TextEncoder().encode(JSON.stringify(body.raw_context)).length;
225	        if (contextSize > MAX_RAW_CONTEXT_BYTES) {
226	            throw new Error('PAYLOAD_TOO_LARGE');
227	        }
228	    }
229	    return body;
230	}
