272	async function resolveActionId(c: Context, body: any, customerId: string): Promise<string> {
273	    // Phase 1: Causal Graph inferred action — use inferred_action_id directly.
274	    // The Proxy interceptor already validated this by watching what the agent called.
275	    if (body.signal_source === 'causal_graph' && body.inferred_action_id && !body.action_name) {
276	        const { data: actionRow } = await supabase
277	            .from('dim_actions')
278	            .select('action_id, action_name')
279	            .eq('action_id', body.inferred_action_id)
280	            .eq('customer_id', customerId)
281	            .maybeSingle();
282	        if (actionRow) {
283	            body.action_name = actionRow.action_name;
284	            return actionRow.action_id;
285	        }
286	        // Not found — fall through to normal resolution path
287	    }
288	
289	    // Path 1: action_id provided (backward compat) — resolve to action_name
290	    if (!body.action_name && (body.action_id_input || body.action_id)) {
291	        const incomingId = body.action_id_input ?? body.action_id;
292	        const { data: actionRow } = await supabase
293	            .from('dim_actions')
294	            .select('action_id, action_name')
295	            .eq('action_id', incomingId)
296	            .eq('customer_id', customerId)
297	            .maybeSingle();
298	
299	        if (actionRow) {
300	            body.action_name = actionRow.action_name;
301	            return actionRow.action_id;
302	        }
303	        // action_id came from our own get_scores response but the action row
304	        // doesn't exist yet (cold-start: scores returned a UUID before dim_actions
305	        // was seeded). Auto-register with a stable name derived from the UUID.
306	        const derivedName = `action_${(incomingId as string).slice(0, 8)}`;
307	        body.action_name = derivedName;
308	        // Fall through to Path 3 — validateAction() will auto-register via upsert.
309	    }
310	
311	    // Path 2: action_name already resolved by middleware
312	    const validatedAction = c.get('validated_action') as any;
313	    if (validatedAction) return validatedAction.action_id;
314	
315	    // Path 3: direct validation
316	    if (!body.action_name) {
317	        throw new Error('UNKNOWN_ACTION:MISSING_FIELD:action_name or action_id is required');
318	    }
319	    const { validateAction } = await import('../middleware/validate-action.js');
320	    const result = await validateAction(body.action_name, customerId, body.action_params);
321	    if (!result.valid) throw new Error(`UNKNOWN_ACTION:${result.error_code ?? 'UNKNOWN_ACTION'}:${result.error}`);
322	    return result.action_id!;
323	}
