1	/**
2	 * Layerinfinite — routes/outcome-feedback.ts
3	 * POST /v1/outcome-feedback
4	 * ══════════════════════════════════════════════════════════════
5	 * Accepts delayed outcome feedback — submitted hours/days after
6	 * the original outcome was logged.
7	 *
8	 * This is the ONE permitted UPDATE path on fact_outcomes.
9	 * Only outcome_score, business_outcome, and feedback_received_at
10	 * are modified. All other columns remain immutable.
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { Hono } from 'hono';
15	import { z } from 'zod';
16	import { supabase } from '../lib/supabase.js';
17	import { invalidateCache } from '../lib/scoring.js';
18	
19	export const outcomeFeedbackRouter = new Hono();
20	
21	const FeedbackBody = z.object({
22	    outcome_id: z.string().uuid(),
23	    final_score: z.number().min(0.0).max(1.0),
24	    // Any string is accepted. Values are normalized to the four canonical
25	    // labels at the application layer. Unknown values map to 'unknown'.
26	    // Field is metadata-only — never read by scoring, trust, or policy.
27	    business_outcome: z
28	        .string()
29	        .min(1)
30	        .max(100)
31	        .transform(val => {
32	            const normalized = val.trim().toLowerCase();
33	            const known = ['resolved', 'partial', 'failed', 'unknown'] as const;
34	            return (known as readonly string[]).includes(normalized)
35	                ? (normalized as typeof known[number])
36	                : 'unknown';
37	        }),
38	    feedback_notes: z.string().max(2000).optional(),
39	});
40	
41	outcomeFeedbackRouter.post('/', async (c) => {
42	    const customerId = c.get('customer_id') as string;
43	
44	    let body: z.infer<typeof FeedbackBody>;
45	    try {
46	        body = FeedbackBody.parse(await c.req.json());
47	    } catch (err: any) {
48	        return c.json(
49	            { error: 'Invalid request body', details: err.errors ?? err.message, code: 'VALIDATION_ERROR' },
50	            400
51	        );
52	    }
53	
54	    // ── Verify outcome belongs to this customer ──────────────
55	    const { data: outcome, error: lookupErr } = await supabase
56	        .from('fact_outcomes')
57	        .select('outcome_id, customer_id, context_id')
58	        .eq('outcome_id', body.outcome_id)
59	        .maybeSingle();
60	
61	    if (lookupErr) {
62	        return c.json({ error: 'Lookup failed', details: lookupErr.message }, 500);
63	    }
64	
65	    if (!outcome || outcome.customer_id !== customerId) {
66	        return c.json({ error: 'Outcome not found', code: 'NOT_FOUND' }, 404);
67	    }
68	
69	    // ── Insert feedback record ───────────────────────────────
70	    const { error: feedbackErr } = await supabase
71	        .from('fact_outcome_feedback')
72	        .insert({
73	            outcome_id: body.outcome_id,
74	            customer_id: customerId,
75	            final_score: body.final_score,
76	            business_outcome: body.business_outcome,
77	            feedback_notes: body.feedback_notes ?? null,
78	        });
79	
80	    if (feedbackErr) {
81	        return c.json({ error: 'Failed to store feedback', details: feedbackErr.message }, 500);
82	    }
83	
84	    // ── Update fact_outcomes with final score ────────────────
85	    // This is the ONE permitted UPDATE on fact_outcomes.
86	    // The prevent_outcome_update trigger allows changes ONLY to
87	    // outcome_score, business_outcome, and feedback_received_at.
88	    const { error: updateErr } = await supabase
89	        .from('fact_outcomes')
90	        .update({
91	            outcome_score: body.final_score,
92	            business_outcome: body.business_outcome,
93	            feedback_received_at: new Date().toISOString(),
94	        })
95	        .eq('outcome_id', body.outcome_id);
96	
97	    if (updateErr) {
98	        return c.json({ error: 'Failed to update outcome', details: updateErr.message }, 500);
99	    }
100	
101	    // ── Trigger score cache refresh (async, non-blocking) ────
102	    invalidateCache(customerId, outcome.context_id);
103	
104	    // ── DELAYED SILENT FAILURE DETECTION (Gap 5) ─────────────
105	    // Original outcome was success=true but feedback shows low score.
106	    (async () => {
107	        const { data: original } = await supabase
108	            .from('fact_outcomes')
109	            .select('success, action_id, agent_id')
110	            .eq('outcome_id', body.outcome_id)
111	            .single();
112	
113	        const isDelayedSilentFailure =
114	            original?.success === true &&
115	            body.final_score < 0.3;
116	
117	        if (isDelayedSilentFailure) {
118	            await supabase.from('degradation_alert_events').insert({
119	                customer_id: customerId,
120	                action_id: original.action_id,
121	                alert_type: 'degradation',
122	                severity: 'warning',
123	                current_value: body.final_score,
124	                baseline_value: 1.0,
125	                message: `Delayed silent failure confirmed: "${body.business_outcome}" — originally logged as success, final score: ${body.final_score}. ${body.feedback_notes || ''}`,
126	            });
127	        }
128	    })().catch(err => {
129	        console.warn('[outcome-feedback] Delayed silent failure check failed:', err);
130	    });
131	
132	    return c.json({
133	        updated: true,
134	        outcome_id: body.outcome_id,
135	        final_score: body.final_score,
136	        business_outcome: body.business_outcome,
137	    });
138	});
