1	/**
2	 * Layerinfinite — lib/scoring.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * 5-Factor Composite Scoring Engine
5	 * ══════════════════════════════════════════════════════════════
6	 *
7	 * FORMULA:
8	 *   composite_score = (
9	 *     w_success  * weighted_success_rate  +
10	 *     w_conf     * confidence             +
11	 *     w_trend    * trend_factor           +
12	 *     w_salience * salience_factor        +
13	 *     w_recency  * recency_factor
14	 *   )
15	 *
16	 * Weights sum to 1.0. All inputs are normalised to [0, 1].
17	 *
18	 * Salience = importance weight of this action (from database).
19	 * Cold-start (confidence < MIN_CONFIDENCE): returns institutional priors.
20	 *
21	 * IN-MEMORY CACHE (5 min TTL):
22	 *   One entry per (action_id, context_id, customer_id).
23	 *   Refreshed on scoring-engine cron or on-demand.
24	 *   Falls back to DB query on cache miss.
25	 */
26	
27	import { supabase, ActionScore } from './supabase.js';
28	
29	// ── Weights ──────────────────────────────────────────────────
30	const W_SUCCESS = 0.40;  // primary driver
31	const W_CONF = 0.20;  // uncertainty penalty
32	const W_TREND = 0.20;  // directional momentum
33	const W_SALIENCE = 0.10;  // action importance
34	const W_RECENCY = 0.10;  // freshness bonus
35	
36	// Bayesian (Laplace) smoothing priors for composite score calculation.
37	// Used in computeCompositeScore(): (successes + α) / (total + α + β).
38	// NOTE: These are NOT used in updateAgentTrust() (outcome-orchestrator.ts),
39	// which uses exponential smoothing independently.
40	export const PRIOR_ALPHA = 1.0;  // Laplace prior successes (neutral = 1)
41	export const PRIOR_BETA  = 1.0;  // Laplace prior failures  (neutral = 1)
42	
43	// ── Thresholds ───────────────────────────────────────────────
44	const MIN_CONFIDENCE = 0.30;  // below this → cold-start fallback
45	const ESCALATION_SCORE = 0.20;  // below this → escalate_human
46	const CACHE_TTL_MS = 5 * 60 * 1000;  // 5 minutes
47	
48	// ── In-Memory Score Cache ─────────────────────────────────────
49	interface CacheEntry {
50	    scores: ScoredAction[];
51	    expires_at: number;
52	}
53	
54	const scoreCache = new Map<string, CacheEntry>();
55	
56	// Evict expired entries every 5 minutes
57	const CLEANUP_INTERVAL_MS = 5 * 60_000;
58	setInterval(() => {
59	    const now = Date.now();
60	    let evicted = 0;
61	    for (const [key, entry] of scoreCache.entries()) {
62	        if (entry.expires_at < now) {
63	            scoreCache.delete(key);
64	            evicted++;
65	        }
66	    }
67	    if (evicted > 0) {
68	        console.info(`[cache-cleanup] Evicted ${evicted} expired entries from scoreCache`);
69	    }
70	}, CLEANUP_INTERVAL_MS).unref();
71	
72	setInterval(() => {
73	    console.info(`[cache-size] scoreCache: ${scoreCache.size} entries`);
74	}, 15 * 60_000).unref();
75	
76	function cacheKey(customerId: string, contextId: string): string {
77	    return `${customerId}:${contextId}`;
78	}
79	
80	export function invalidateCache(customerId?: string, contextId?: string): void {
81	    if (customerId && contextId) {
82	        scoreCache.delete(cacheKey(customerId, contextId));
83	    } else {
84	        scoreCache.clear();
85	    }
86	}
87	
88	/**
89	 * Returns the cached composite score for a specific action in a context.
90	 * Used by log-outcome.ts for salience sampling:
91	 *   if (score > 0.9 && success) → salience = 0.1 (sampled down)
92	 * Returns null on cache miss (caller defaults to salience=1.0).
93	 */
94	export function getCachedScore(
95	    actionId: string,
96	    contextId: string,
97	    customerId: string
98	): number | null {
99	    // Scan the cache for this customer+context
100	    const key = cacheKey(customerId, contextId);
101	    const cached = scoreCache.get(key);
102	    if (!cached || cached.expires_at <= Date.now()) return null;
103	
104	    const match = cached.scores.find(s => s.action_id === actionId);
105	    return match ? match.composite_score : null;
106	}
107	
108	// ── Scoring types ─────────────────────────────────────────────
109	export type TrendLabel = 'stable' | 'improving' | 'degrading' | 'critical';
110	
111	export function trendLabel(trendDelta: number | null): TrendLabel {
112	    if (trendDelta === null) return 'stable';
113	    if (trendDelta < -0.15) return 'critical';
114	    if (trendDelta < -0.05) return 'degrading';
115	    if (trendDelta > 0.05) return 'improving';
116	    return 'stable';
117	}
118	
119	export interface ScoredAction {
120	    action_id: string;
121	    action_name: string;
122	    action_category: string;
123	    composite_score: number;
124	    confidence: number;
125	    trend_delta: number | null;
126	    trend: TrendLabel;
127	    total_attempts: number;
128	    is_cold_start: boolean;
129	    is_low_sample: boolean;
130	    recommendation: 'recommend' | 'neutral' | 'avoid' | 'escalate';
131	}
132	
133	export interface ScoringResult {
134	    ranked_actions: ScoredAction[];
135	    top_action: ScoredAction;
136	    should_escalate: boolean;
137	    cold_start: boolean;
138	    context_id: string;
139	    customer_id: string;
140	    view_refreshed_at: string | null;
141	    served_from_cache: boolean;
142	}
143	
144	// ── 5-Factor scoring formula ─────────────────────────────────
145	/**
146	 * @param contextMatch — cosine similarity from context-embed.ts.
147	 *   null means exact match (fallback) → treated as 1.0.
148	 */
149	export function computeCompositeScore(row: ActionScore, contextMatch: number | null = null): number {
150	    // Factor 1: Weighted success rate (primary)
151	    // Applied Bayesian smoothing (Laplace / Beta distribution prior):
152	    const rawSuccessRate = row.weighted_success_rate ?? row.raw_success_rate ?? 0;
153	    const n = row.total_attempts ?? 0;
154	
155	    // Bayesian smoothed rate:
156	    // (successes + alpha) / (total + alpha + beta)
157	    const f_success = (rawSuccessRate * n + PRIOR_ALPHA) / (n + PRIOR_ALPHA + PRIOR_BETA);
158	
159	    // Factor 2: Confidence (Wilson-style: n/(n+10))
160	    const f_conf = row.confidence ?? 0;
161	
162	    // Factor 3: Trend delta → normalised to [0,1]
163	    const rawTrend = row.trend_delta ?? 0;
164	    const f_trend = Math.max(0, Math.min(1, (rawTrend + 0.5)));
165	
166	    // Factor 4: Salience — currently 1.0 per row (Phase 5 extensibility)
167	    const f_salience = 1.0;
168	
169	    // Factor 5: Recency — bonus if last outcome < 24h ago
170	    let f_recency = 0.5;  // neutral default
171	    if (row.last_outcome_at) {
172	        const ageHours = (Date.now() - new Date(row.last_outcome_at).getTime()) / 3_600_000;
173	        f_recency = Math.max(0, Math.min(1, 1 - (ageHours / 168)));  // decay over 7 days
174	    }
175	
176	    // Context match factor: null → 1.0 (exact match assumed)
177	    const f_context = contextMatch ?? 1.0;
178	
179	    return (
180	        W_SUCCESS * f_success +
181	        W_CONF * f_conf +
182	        W_TREND * f_trend +
183	        W_SALIENCE * f_salience +
184	        W_RECENCY * f_recency
185	    ) * f_context;  // scale by context similarity
186	}
187	
188	function toRecommendation(score: number, isEscalate: boolean): ScoredAction['recommendation'] {
189	    if (isEscalate) return 'escalate';
190	    if (score >= 0.65) return 'recommend';
191	    if (score >= 0.40) return 'neutral';
192	    return 'avoid';
193	}
