284	// ── Public API ────────────────────────────────────────────────
285	export async function getScores(
286	    customerId: string,
287	    contextId: string,
288	    contextType?: string,
289	    forceRefresh = false,
290	    contextMatch: number | null = null
291	): Promise<ScoringResult> {
292	    const key = cacheKey(customerId, contextId);
293	    const cached = scoreCache.get(key);
294	
295	    // Serve from cache if valid and not forced
296	    if (!forceRefresh && cached && cached.expires_at > Date.now()) {
297	        const top = cached.scores[0];
298	        return {
299	            ranked_actions: cached.scores,
300	            top_action: top,
301	            should_escalate: top?.composite_score < ESCALATION_SCORE,
302	            cold_start: top?.is_cold_start ?? false,
303	            context_id: contextId,
304	            customer_id: customerId,
305	            view_refreshed_at: null,
306	            served_from_cache: true,
307	        };
308	    }
309	
310	    // Fetch from materialized view
311	    const { scores: rawScores, view_refreshed_at } = await fetchScoresFromDB(customerId, contextId);
312	
313	    let scoredActions: ScoredAction[];
314	    let isColdStart = false;
315	
316	    if (rawScores.length === 0 || rawScores.every(r => r.confidence < MIN_CONFIDENCE)) {
317	        isColdStart = true;
318	
319	        // Tier 2: context-specific institutional priors
320	        let fallback = contextType
321	            ? await fetchInstitutionalFallback(contextType)
322	            : [];
323	
324	        // Tier 3: global fallback — ranked_actions is NEVER empty after migration 066
325	        if (fallback.length === 0) {
326	            console.info(
327	                `[scoring] No priors for context_type="${contextType ?? 'none'}". ` +
328	                `Using global fallback.`
329	            );
330	            fallback = await fetchGlobalFallback();
331	        }
332	
333	        scoredActions = fallback;
334	    } else {
335	        scoredActions = rawScores.map((row): ScoredAction => {
336	            const score = computeCompositeScore(row, contextMatch);
337	            return {
338	                action_id: row.action_id,
339	                action_name: row.action_name,
340	                action_category: row.action_category,
341	                composite_score: Math.round(score * 10000) / 10000,
342	                confidence: row.total_attempts < 3 ? Math.min(row.confidence, 0.25) : row.confidence,
343	                trend_delta: row.trend_delta,
344	                trend: trendLabel(row.trend_delta),
345	                total_attempts: row.total_attempts,
346	                is_cold_start: false,
347	                is_low_sample: row.total_attempts < 3,
348	                recommendation: toRecommendation(score, false),
349	            };
350	        }).sort((a, b) => b.composite_score - a.composite_score);
351	    }
352	
353	    // Store in cache
354	    scoreCache.set(key, { scores: scoredActions, expires_at: Date.now() + CACHE_TTL_MS });
355	
356	    const top = scoredActions[0] ?? null;
357	
358	    return {
359	        ranked_actions: scoredActions,
360	        top_action: top,
361	        should_escalate: !top || top.composite_score < ESCALATION_SCORE,
362	        cold_start: isColdStart,
363	        context_id: contextId,
364	        customer_id: customerId,
365	        view_refreshed_at: view_refreshed_at,
366	        served_from_cache: false,
367	    };
368	}
369	
370	// Export constants for tests
371	export { MIN_CONFIDENCE, ESCALATION_SCORE, W_SUCCESS, W_CONF, W_TREND, W_SALIENCE, W_RECENCY };
372	
373	/**
374	 * Compute the effective score for an outcome.
375	 * If outcome_score is provided and valid (0.0–1.0), use it.
376	 * Otherwise fall back to binary: success=1.0, failure=0.0.
377	 *
378	 * This mirrors the DB-level COALESCE(outcome_score, success::FLOAT)
379	 * used in mv_action_scores, but for application-level logic.
380	 */
381	export function computeEffectiveScore(
382	    success: boolean,
383	    outcomeScore?: number
384	): number {
385	    if (outcomeScore !== undefined && outcomeScore >= 0.0 && outcomeScore <= 1.0) {
386	        return outcomeScore;
387	    }
388	    return success ? 1.0 : 0.0;
389	}
