25	// ── Register action schema ────────────────────────────────────
26	const RegisterActionBody = z.object({
27	    action_name: z.string().min(1).max(255),
28	    // Any string is accepted. Value is normalized to lowercase.
29	    // 'custom' is the default for callers that omit the field.
30	    // Field is a display label — scoring.ts passes it through as-is,
31	    // no branching or scoring weight applied.
32	    action_category: z
33	        .string()
34	        .max(100)
35	        .optional()
36	        .default('custom')
37	        .transform(val => val.trim().toLowerCase()),
38	    action_description: z.string().max(1000).optional(),
39	    required_params: z.array(z.string()).optional().default([]),
40	    validation_mode: z.string().optional().default('none'),
41	});
