43	function getCustomerId(c: any): string | null {
44	    return ((c as any).get('customerId') ?? c.get('customer_id') ?? null) as string | null;
45	}
46	
47	async function registerActionHandler(c: any) {
48	    const customerId = getCustomerId(c);
49	    if (!customerId) {
50	        return c.json({ error: 'Unauthorized' }, 401);
51	    }
52	
53	    let body: z.infer<typeof RegisterActionBody>;
54	    try {
55	        body = RegisterActionBody.parse(await c.req.json());
56	    } catch (err: any) {
57	        return c.json({ error: 'Invalid request body', details: err.errors ?? err.message }, 400);
58	    }
59	
60	    const { data, error } = await supabase
61	        .from('dim_actions')
62	        .insert({
63	            action_name: body.action_name,
64	            action_category: body.action_category,
65	            action_description: body.action_description ?? null,
66	            required_params: body.required_params,
67	            validation_mode: body.validation_mode ?? 'none',
68	            is_active: true,
69	            customer_id: customerId,
70	        })
71	        .select('action_id, action_name, action_category, is_active, customer_id, created_at')
72	        .single();
73	
74	    if (error) {
75	        if (error.code === '23505') {
76	            return c.json(
77	                { error: `Action "${body.action_name}" already exists.`, code: 'DUPLICATE' },
78	                409
79	            );
80	        }
81	        return c.json({ error: 'Failed to register action', details: error.message }, 500);
82	    }
83	
84	    invalidateActionCache(body.action_name);
85	
86	    return c.json({
87	        success: true,
88	        action: data,
89	        message: `Action "${body.action_name}" registered. Agents can now log outcomes with this action.`,
90	    }, 201);
91	}
