134	async function toggleActionHandler(c: any) {
135	    const customerId = getCustomerId(c);
136	    if (!customerId) {
137	        return c.json({ error: 'Unauthorized' }, 401);
138	    }
139	
140	    const actionId = c.req.param('id');
141	
142	    let body: { is_active?: boolean };
143	    try {
144	        body = await c.req.json();
145	    } catch {
146	        return c.json({ error: 'Invalid JSON body' }, 400);
