1	/**
2	 * Layerinfinite — lib/policy-engine.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Explore / Exploit / Escalate decision tree.
5	 *
6	 * This file contains ZERO database calls. It is a pure function
7	 * that takes ranked actions + trust + config and returns a
8	 * deterministic policy decision.
9	 *
10	 * randomFn is injectable for testing (deterministic in tests).
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { ScoredAction } from './scoring.js';
15	
16	// ── Input types ──────────────────────────────────────────────
17	
18	export interface AgentTrustScore {
19	    trust_score: number;       // 0.0–1.0
20	    trust_status: 'trusted' | 'probation' | 'sandbox' | 'suspended' | 'new' | 'degraded';
21	    consecutive_failures: number;
22	}
23	
24	export interface CustomerPolicyConfig {
25	    risk_tolerance: 'conservative' | 'balanced' | 'aggressive';
26	    escalation_score: number;  // below this → escalate (default 0.2)
27	    exploration_rate: number;  // epsilon for epsilon-greedy (default 0.05)
28	    min_confidence: number;  // below this → cold start (default 0.3)
29	}
30	
31	export interface PolicyDecision {
32	    policy: 'exploit' | 'explore' | 'escalate' | 'SANDBOX';
33	    reason: string;
34	    selectedAction: string | null;
35	    explorationTarget: string | null;
36	    human_review_required?: boolean;
37	    sandbox_message?: string;
38	}
39	
40	// ── Default config (used when customer config is missing) ────
41	
42	export const DEFAULT_POLICY_CONFIG: CustomerPolicyConfig = {
43	    risk_tolerance: 'balanced',
44	    escalation_score: 0.20,
45	    exploration_rate: 0.05,
46	    min_confidence: 0.30,
47	};
48	
49	export const DEFAULT_TRUST: AgentTrustScore = {
50	    trust_score: 0.5,
51	    trust_status: 'probation',  // 0.5 is in the probation band (0.3–0.6); 'trusted' was overly permissive
52	    consecutive_failures: 0,
53	};
54	
55	// ── Decision tree ────────────────────────────────────────────
56	
57	export function getPolicyDecision(
58	    params: {
59	        rankedActions: ScoredAction[];
60	        agentTrust: AgentTrustScore | null | undefined;
61	        customerConfig: CustomerPolicyConfig;
62	        coldStartActive: boolean;
63	    },
64	    randomFn: () => number = Math.random
65	): PolicyDecision {
66	    // ── FIX: null guard — use DEFAULT_TRUST if trust not available ──
67	    const agentTrust = params.agentTrust ?? DEFAULT_TRUST;
68	    const { rankedActions, customerConfig, coldStartActive } = params;
69	
70	    // ── Rule 1: Suspended agent → always escalate ─────────────
71	    if (agentTrust.trust_status === 'suspended') {
72	        return {
73	            policy: 'escalate',
74	            reason: 'agent_suspended',
75	            selectedAction: null,
76	            explorationTarget: null,
77	            human_review_required: true,
78	        };
79	    }
80	
81	    const topAction = rankedActions[0];
82	
83	    // ── Rule 1.3: New agent (no history) → force explore ──────
84	    // A 'new' agent has zero outcomes. Exploiting an uninformed prior would
85	    // be misleading. Force exploration to gather real signal first.
86	    if (agentTrust.trust_status === 'new') {
87	        const target = rankedActions.length > 0
88	            ? [...rankedActions].sort((a, b) => a.total_attempts - b.total_attempts)[0]
89	            : null;
90	        return {
91	            policy: 'explore',
92	            reason: 'agent_new_no_history',
93	            selectedAction: null,
94	            explorationTarget: target?.action_id ?? null,
95	        };
96	    }
97	
98	    // ── Rule 1.4: Degraded agent → sandbox-like (review required)
99	    // 'degraded' sits between probation and sandbox: still executes but
100	    // every action requires human review until the score recovers.
101	    if (agentTrust.trust_status === 'degraded') {
102	        return {
103	            policy: 'SANDBOX',
104	            reason: 'agent_degraded',
105	            selectedAction: topAction?.action_id ?? null,
106	            explorationTarget: null,
107	            human_review_required: true,
108	            sandbox_message: 'Agent is in degraded state. ' +
109	                'Actions will execute but require human review. ' +
110	                `Trust score: ${agentTrust.trust_score.toFixed(3)}. ` +
111	                `Threshold to exit degraded: 0.3`,
112	        };
113	    }
114	
115	    // ── Rule 1.5: Sandbox agent → flag for review but execute top action
116	    if (agentTrust.trust_status === 'sandbox') {
117	        return {
118	            policy: 'SANDBOX',
119	            reason: 'agent_in_sandbox_probation',
120	            selectedAction: topAction?.action_id ?? null,
121	            explorationTarget: null,
122	            human_review_required: true,
123	            sandbox_message: 'Agent is in sandbox mode. ' +
124	                'All actions will execute but require human review. ' +
125	                `Trust score: ${agentTrust.trust_score.toFixed(3)}. ` +
126	                `Threshold to exit sandbox: 0.3`,
127	        };
128	    }
129	
130	    // ── Rule 2: Cold start OR all confidence < threshold ──────
131	    const allLowConfidence = rankedActions.length > 0 &&
132	        rankedActions.every(a => a.confidence < customerConfig.min_confidence);
133	
134	    if (coldStartActive || allLowConfidence) {
135	        // Suggest the action with the lowest sample count (most exploration value)
136	        const target = rankedActions.length > 0
137	            ? [...rankedActions].sort((a, b) => a.total_attempts - b.total_attempts)[0]
138	            : null;
139	
140	        return {
141	            policy: 'explore',
142	            reason: 'cold_start',
143	            selectedAction: null,
144	            explorationTarget: target?.action_id ?? null,
145	        };
146	    }
147	
148	    if (!topAction) {
149	        return {
150	            policy: 'escalate',
151	            reason: 'no_actions_available',
152	            selectedAction: null,
153	            explorationTarget: null,
154	            human_review_required: true,
155	        };
156	    }
157	
158	    const topScore = topAction.composite_score;
159	    const topConf = topAction.confidence;
160	
161	    // ── Rule 3: Conservative + top > 0.8 → always exploit ─────
162	    if (customerConfig.risk_tolerance === 'conservative' && topScore > 0.8) {
163	        return {
164	            policy: 'exploit',
165	            reason: 'conservative_high_score',
166	            selectedAction: topAction.action_id,
167	            explorationTarget: null,
168	        };
169	    }
170	
171	    // ── Rule 4: High score + high confidence → epsilon-greedy ─
172	    if (topScore > 0.85 && topConf > 0.8) {
173	        const roll = randomFn();
174	        if (roll < customerConfig.exploration_rate) {
175	            // Explore: pick 2nd action (or lowest-sample action)
176	            const exploreTarget = rankedActions.length > 1
177	                ? rankedActions[1]
178	                : topAction;
179	
180	            return {
181	                policy: 'explore',
182	                reason: 'epsilon_greedy_explore',
183	                selectedAction: null,
184	                explorationTarget: exploreTarget.action_id,
185	            };
186	        }
187	        return {
188	            policy: 'exploit',
189	            reason: 'epsilon_greedy_exploit',
190	            selectedAction: topAction.action_id,
191	            explorationTarget: null,
192	        };
193	    }
194	
195	    // ── Rule 5: Medium score (0.5–0.85) → exploit with probability
196	    if (topScore >= 0.5 && topScore <= 0.85) {
197	        const exploitProbability = topConf;  // confidence × 100%
198	        const roll = randomFn();
199	
200	        if (roll < exploitProbability) {
201	            return {
202	                policy: 'exploit',
203	                reason: 'confidence_weighted_exploit',
204	                selectedAction: topAction.action_id,
205	                explorationTarget: null,
206	            };
207	        }
208	        // Explore the 2nd-best action
209	        const exploreTarget = rankedActions.length > 1
210	            ? rankedActions[1]
211	            : topAction;
212	        return {
213	            policy: 'explore',
214	            reason: 'confidence_weighted_explore',
215	            selectedAction: null,
216	            explorationTarget: exploreTarget.action_id,
217	        };
218	    }
219	
220	    // ── Rule 6: All scores < escalation threshold → escalate ──
221	    if (rankedActions.every(a => a.composite_score < customerConfig.escalation_score)) {
222	        return {
223	            policy: 'escalate',
224	            reason: 'no_reliable_action',
225	            selectedAction: null,
226	            explorationTarget: null,
227	        };
228	    }
229	
230	    // ── Rule 7: Default → explore 2nd action ──────────────────
231	    const fallbackTarget = rankedActions.length > 1
232	        ? rankedActions[1]
233	        : topAction;
234	
235	    return {
236	        policy: 'explore',
237	        reason: 'default_exploration',
238	        selectedAction: null,
239	        explorationTarget: fallbackTarget.action_id,
240	    };
241	}
