1	import { Context } from 'hono';
2	import { supabase } from '../lib/supabase.js';
3	
4	type Provider = 'stripe' | 'sendgrid' | 'generic';
5	type BusinessOutcome = 'resolved' | 'partial' | 'failed' | 'unknown';
6	
7	interface CanonicalWebhookPayload {
8	    outcomeId: string;
9	    finalScore: number;
10	    businessOutcome: BusinessOutcome;
11	}
12	
13	function clamp01(value: number): number {
14	    if (value < 0) return 0;
15	    if (value > 1) return 1;
16	    return value;
17	}
18	
19	function extractStripePayload(payload: Record<string, unknown>): CanonicalWebhookPayload | null {
20	    const metadata = (payload.metadata ?? {}) as Record<string, unknown>;
21	    const outcomeId = metadata.layerinfinite_outcome_id;
22	    const amountRefunded = Number(payload.amount_refunded ?? 0);
23	    const amount = Number(payload.amount ?? 0);
24	    const status = String(payload.status ?? '');
25	
26	    if (typeof outcomeId !== 'string') return null;
27	
28	    const finalScore = amount > 0 ? clamp01(amountRefunded / amount) : 0.5;
29	    const businessOutcome: BusinessOutcome = status === 'succeeded' ? 'resolved' : 'failed';
30	
31	    return { outcomeId, finalScore, businessOutcome };
32	}
33	
34	function extractSendgridPayload(payload: Record<string, unknown>): CanonicalWebhookPayload | null {
35	    const customArgs = (payload.custom_args ?? {}) as Record<string, unknown>;
36	    const outcomeId = customArgs.outcome_id;
37	    const event = String(payload.event ?? '');
38	
39	    if (typeof outcomeId !== 'string') return null;
40	
41	    const finalScore = event === 'delivered' ? 1.0 : event === 'bounce' ? 0.0 : 0.5;
42	    const businessOutcome: BusinessOutcome = event === 'delivered' ? 'resolved' : 'failed';
43	
44	    return { outcomeId, finalScore, businessOutcome };
45	}
46	
47	function extractGenericPayload(payload: Record<string, unknown>): CanonicalWebhookPayload | null {
48	    const outcomeId = payload.outcome_id;
49	    const finalScore = Number(payload.final_score);
50	    const businessOutcome = String(payload.business_outcome) as BusinessOutcome;
51	
52	    const allowedOutcomes = ['resolved', 'partial', 'failed', 'unknown'];
53	    if (typeof outcomeId !== 'string') return null;
54	    if (Number.isNaN(finalScore)) return null;
55	    if (!allowedOutcomes.includes(businessOutcome)) return null;
56	
57	    return {
58	        outcomeId,
59	        finalScore: clamp01(finalScore),
60	        businessOutcome,
61	    };
62	}
63	
64	function extractPayload(provider: Provider, payload: Record<string, unknown>): CanonicalWebhookPayload | null {
65	    if (provider === 'stripe') return extractStripePayload(payload);
66	    if (provider === 'sendgrid') return extractSendgridPayload(payload);
67	    return extractGenericPayload(payload);
68	}
69	
70	export default async function webhookRoute(c: Context): Promise<Response> {
71	    try {
72	        const provider = c.req.param('provider') as Provider;
73	        if (!['stripe', 'sendgrid', 'generic'].includes(provider)) {
74	            return c.json({ resolved: false }, 200);
75	        }
76	
77	        const rawPayload = await c.req.json();
78	        const payload = extractPayload(provider, (rawPayload ?? {}) as Record<string, unknown>);
79	
80	        if (!payload) {
81	            return c.json({ resolved: false }, 200);
82	        }
83	
84	        const { data: pending } = await supabase
85	            .from('dim_pending_signal_registrations')
86	            .select('id, customer_id, is_resolved')
87	            .eq('outcome_id', payload.outcomeId)
88	            .eq('is_resolved', false)
89	            .limit(1)
90	            .maybeSingle();
91	
92	        if (!pending) {
93	            return c.json({ resolved: false, outcome_id: payload.outcomeId }, 200);
94	        }
95	
96	        await supabase
97	            .from('dim_pending_signal_registrations')
98	            .update({
99	                is_resolved: true,
100	                resolved_at: new Date().toISOString(),
101	                final_score: payload.finalScore,
102	            })
103	            .eq('id', pending.id);
104	
105	        await supabase
106	            .from('fact_outcomes')
107	            .update({
108	                outcome_score: payload.finalScore,
109	                business_outcome: payload.businessOutcome,
110	                feedback_received_at: new Date().toISOString(),
111	            })
112	            .eq('outcome_id', payload.outcomeId);
113	
114	        return c.json({ resolved: true, outcome_id: payload.outcomeId }, 200);
115	    } catch {
116	        return c.json({ resolved: false }, 200);
117	    }
118	}
