### 8. CLIENT LAYER (HTTP Wrapper)

The MCP server calls the existing REST API internally. It does NOT call Supabase or DB directly. This ensures:

- The MCP server stays in sync with the REST API (single source of truth for business logic).
- The MCP server does not need direct DB credentials.
- The REST API's middleware (auth, rate limiting, action validation) applies transparently.

```typescript
// src/lib/client.ts
export class LayerInfiniteClient {
  private baseUrl: string;
  private apiKey: string;
  private adminKey: string | null;

  constructor(config: { baseUrl: string; apiKey: string; adminKey?: string }) {
    this.baseUrl = config.baseUrl;
    this.apiKey = config.apiKey;
    this.adminKey = config.adminKey ?? null;
  }

  private async request(method: string, path: string, body?: any, isAdmin = false) {
    const headers: Record<string, string> = {
      "X-API-Key": isAdmin && this.adminKey ? this.adminKey : this.apiKey,
      "Content-Type": "application/json",
    };
    if (isAdmin && this.adminKey) {
      headers["X-Admin-Key"] = this.adminKey;
    }

    const response = await fetch(`${this.baseUrl}${path}`, {
      method,
      headers,
      body: body ? JSON.stringify(body) : undefined,
    });

    const responseBody = await response.json().catch(() => null);

    if (!response.ok) {
      throw mapRestError(response.status, responseBody);
    }

    return responseBody;
  }

  // --- Agent Tools ---
  async postLogOutcome(params: any) {
    return this.request("POST", "/v1/log-outcome", params);
  }

  async getScores(params: { context_id?: string; issue_type?: string; top_n?: number; force_refresh?: boolean }) {
    const query = new URLSearchParams();
    if (params.context_id) query.set("context_id", params.context_id);
    if (params.issue_type) query.set("issue_type", params.issue_type);
    if (params.top_n) query.set("top_n", String(params.top_n));
    if (params.force_refresh) query.set("refresh", "true");
    return this.request("GET", `/v1/get-scores?${query.toString()}`);
  }

  async getPatterns(params: { context_id?: string; issue_type?: string; min_samples?: number; top_n?: number }) {
    const query = new URLSearchParams();
    if (params.context_id) query.set("context_id", params.context_id);
    if (params.issue_type) query.set("issue_type", params.issue_type);
    if (params.min_samples) query.set("min_samples", String(params.min_samples));
    if (params.top_n) query.set("top_n", String(params.top_n));
    return this.request("GET", `/v1/get-patterns?${query.toString()}`);
  }

  async getAudit(params: { cursor?: string; session_id?: string; agent_id?: string; action_name?: string; limit?: number }) {
    const query = new URLSearchParams();
    if (params.cursor) query.set("cursor", params.cursor);
    if (params.session_id) query.set("session_id", params.session_id);
    if (params.agent_id) query.set("agent_id", params.agent_id);
    if (params.action_name) query.set("action_name", params.action_name);
    if (params.limit) query.set("limit", String(params.limit));
    return this.request("GET", `/v1/audit?${query.toString()}`);
  }

  async submitOutcomeFeedback(params: { outcome_id: string; final_score: number; business_outcome: string; feedback_notes?: string }) {
    return this.request("POST", "/v1/outcome-feedback", params);
  }

  async simulate(params: any) {
    return this.request("POST", "/v1/simulate", params);
  }

  // --- Admin Tools ---
  async adminRegisterAction(params: { action_name: string; action_category?: string; action_description?: string }) {
    return this.request("POST", "/v1/admin/register-action", params, true);
  }

  async adminListActions() {
    return this.request("GET", "/v1/admin/actions", undefined, true);
  }

  async adminToggleAction(id: string, isActive: boolean) {
    return this.request("PUT", `/v1/admin/actions/${id}`, { is_active: isActive }, true);
  }

  async adminReinstateAgent(params: { agent_id: string; reinstated_by: string }) {
    return this.request("POST", "/v1/admin/reinstate-agent", params, true);
  }
}
```

