### 9. SERVER BOOTSTRAP (Dual Transport)

```typescript
// src/index.ts
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { SSEServerTransport } from "@modelcontextprotocol/sdk/server/sse.js";
import { registerAllResources } from "./resources/index.js";
import { registerAllTools } from "./tools/index.js";
import { registerAllPrompts } from "./prompts/index.js";
import { LayerInfiniteClient } from "./lib/client.js";
import { loadConfig } from "./lib/config.js";

const config = loadConfig();

const client = new LayerInfiniteClient({
  baseUrl: config.baseUrl,
  apiKey: config.apiKey,
  adminKey: config.adminKey,
});

const server = new McpServer({
  name: "LayerInfinite Decision Intelligence",
  version: "1.0.0",
  // Server-wide context available to all handlers
  serverContext: { apiClient: client, config },
});

// Register all resources, tools, and prompts
registerAllResources(server);
registerAllTools(server);
registerAllPrompts(server);

async function main() {
  if (config.transport === "sse") {
    // SSE mode: wraps an Express server
    const express = await import("express");
    const app = express.default();
    const transports = new Map<string, SSEServerTransport>();

    app.get("/sse", async (req, res) => {
      const transport = new SSEServerTransport("/messages", res);
      transports.set(transport.sessionId, transport);
      res.on("close", () => transports.delete(transport.sessionId));
      await server.connect(transport);
    });

    app.post("/messages", async (req, res) => {
      const sessionId = req.query.sessionId as string;
      const transport = transports.get(sessionId);
      if (transport) {
        await transport.handlePostMessage(req, res);
      } else {
        res.status(404).send("Session not found");
      }
    });

    app.listen(config.port!, () => {
      console.log(`LayerInfinite MCP server (SSE) running on port ${config.port}`);
    });
  } else {
    // stdio mode: for local clients
    const transport = new StdioServerTransport();
    await server.connect(transport);
  }
}

main().catch(console.error);
```

